<template>
    <div class="app-main">
        <nav-view v-if="$route.name!='about'" id="navTop" :class="{'navbar-fixed': isFixed }" />
        <main class="main" :class="{'navbar-fixed-top': isFixed }">
            <transition name="aside">
                <router-view />
            </transition>
        </main>
        <footer-view />
        <back-top />
    </div>
</template>
<script>
import NavView from './nav';
import FooterView from './footer';
import BackTop from '@/components/backTop';
export default {
    data() {
        return {
            isFixed: false,
            offsetTop: 0
        }
    },
    components: {
        NavView,
        FooterView,
        BackTop
    },
    mounted() {
        window.addEventListener('scroll', this.handleScroll);
        this.$nextTick(() => {
            this.offsetTop = document.querySelector('#navTop').offsetTop;
        })
    },
    destroyed() {
        window.removeEventListener('scroll', this.handleScroll)
    },
    methods:{
        handleScroll() {
            // 设置或获取位于对象最顶端和窗口中可见内容的最顶端之间的距离 (被卷曲的高度)
            var scrollTop = window.pageYOffset || document.documentElement.scrollTop || document.body.scrollTop
            //如果被卷曲的高度大于吸顶元素到顶端位置 的距离
            this.isFixed = scrollTop > this.offsetTop+40 ? true : false;
        }
    }
}
</script>
<style lang="scss" scoped>
.app-main{
    position: relative;
    min-height: 100vh;
    transition: all 0.2s ease-in-out;
    display: flex;
    flex-direction: column;
    flex: auto;
    .main{
        flex: auto;
        padding-top: 90px;
        @include font_color($font-color-light);
        @include bg_color($background-color-light);
    }
}
</style>


