<template>
    <nav is="nav" class="navbar">
        <div class="container">
            <div class="nav-logo">
                <router-link to="/">
                    logo
                </router-link>
            </div>
            <div class="nav-list flex">
                <router-link class="item" to="/">
                    <i class=""></i>
                    <span>首页</span>
                </router-link>
                <router-link class="item" to="/gank">
                    <i class=""></i>
                    <span>福利</span>
                </router-link>
                <router-link class="item" to="/about">
                    <i class=""></i>
                    <span>关于</span>
                </router-link>
                <a class="item" @click="changeTheme">{{theme=='light'?'dark':'light'}}</a>
            </div>
        </div>
    </nav>
</template>
<script>
import { mapState } from 'vuex';
export default {
    computed: {
        ...mapState({
            theme: state => state.app.theme
        })
    },
    mounted(){
        if(this.theme == 'light') {
            window.document.documentElement.setAttribute('data-theme', 'light')
        } else {
            window.document.documentElement.setAttribute('data-theme', 'dark')
        }
    },
    methods: {
        changeTheme() {
            if(this.theme == 'light') {
                this.$store.dispatch('ToggleTheme', 'dark');
                window.document.documentElement.setAttribute('data-theme', 'dark')
            } else {
                this.$store.dispatch('ToggleTheme', 'light');
                window.document.documentElement.setAttribute('data-theme', 'light')
            }
        }
    }
}
</script>


